214	// runBundleInlineAllowed reports whether a path qualifies for inline content
215	// based on extension and exact-filename whitelist rules from Story 16.
216	func runBundleInlineAllowed(path string) bool {
217		base := strings.ToLower(filepath.Base(filepath.FromSlash(path)))
218		if runBundleInlineExtensions[base] {
219			return true
220		}
221		ext := strings.ToLower(filepath.Ext(base))
222		return runBundleInlineExtensions[ext]
223	}
