225	// mimeTypeForPath returns a best-effort MIME type from the file extension.
226	// Falls back to application/octet-stream when nothing matches.
227	func mimeTypeForPath(path string) string {
228		ext := strings.ToLower(filepath.Ext(path))
229		switch ext {
230		case ".md":
231			return "text/markdown"
232		case ".txt":
233			return "text/plain"
234		case ".json":
235			return "application/json"
236		case ".jsonl":
237			return "application/x-ndjson"
238		case ".log":
239			return "text/plain"
240		}
241		if mt := mime.TypeByExtension(ext); mt != "" {
242			return mt
243		}
244		return "application/octet-stream"
245	}
