64	// TestRunBundleFile_SizeCap covers AC: files >64KB return truncated=true with
65	// sizeBytes populated and no inline content.
66	func TestRunBundleFile_SizeCap(t *testing.T) {
67		workDir, bundleID := setupRunBundleFixture(t)
68		bundleRoot := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, bundleID)
69		bigPath := filepath.Join(bundleRoot, "big.md")
70		body := strings.Repeat("a", runBundleInlineMaxBytes+1)
71		if err := os.WriteFile(bigPath, []byte(body), 0o644); err != nil {
72			t.Fatal(err)
73		}
74		state := stateWithProject(workDir)
75		out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, "big.md")
76		if !ok || out == nil {
77			t.Fatal("expected file metadata, got nil")
78		}
79		if !out.Truncated {
80			t.Fatal("expected truncated=true for >64KB file")
81		}
82		if out.Content != nil {
83			t.Fatalf("expected no inline content for >64KB file, got %d bytes", len(*out.Content))
84		}
85		if out.SizeBytes != runBundleInlineMaxBytes+1 {
86			t.Fatalf("expected sizeBytes=%d, got %d", runBundleInlineMaxBytes+1, out.SizeBytes)
87		}
